#[test]
fn test_contains_expected_flags() {
    let help = UpdateArgs::available_flags_help();

    // Verify all expected flags are present
    let expected_flags = [
        "--title",
        "--description",
        "--status",
        "--priority",
        "--assignee",
        "--no-assignee",
        "--design",
        "--acceptance",
        "--notes",
        "--external-ref",
    ];

    for flag in expected_flags {
        assert!(
            help.contains(flag),
            "Expected flag '{}' not found in help: {}",
            flag,
            help
        );
    }
}

